Fix this topological sort implementation. It fails when there are disconnected nodes.

```python
def topo_sort(graph: dict) -> list:
    visited = set()
    result = []
    def dfs(node):
        visited.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                dfs(neighbor)
        result.append(node)
    for node in graph:
        if node not in visited:
            dfs(node)
    return result
```

The function should return nodes in topological order (dependencies first).

```diff
--- a/src/solution.py
+++ b/src/solution.py
@@ -7,7 +7,7 @@
         for neighbor in graph.get(node, []):
             if neighbor not in visited:
                 dfs(neighbor)
-        result.append(node)
+        result.insert(0, node)
     for node in graph:
         if node not in visited:
             dfs(node)
```

Fix this topological sort. It doesn't detect cycles.

```python
def topo_sort_safe(graph: dict) -> dict:
    visited = set()
    order = []
    def dfs(node):
        visited.add(node)
        for dep in graph.get(node, []):
            if dep not in visited:
                dfs(dep)
        order.append(node)
    for node in graph:
        if node not in visited:
            dfs(node)
    order.reverse()
    return {'order': order, 'is_valid': True, 'cycle': None}
```

Fix: indegree calculation is wrong. Missing nodes that have no incoming edges.

```python
def kahn_sort(tasks: list) -> list:
    graph = {}
    indegree = {}
    for t in tasks:
        graph[t['id']] = t['depends_on']
        for dep in t['depends_on']:
            indegree[dep] = indegree.get(dep, 0) + 1
    queue = [n for n in graph if indegree.get(n, 0) == 0]
    order = []
    while queue:
        node = queue.pop(0)
        order.append(node)
        for neighbor in graph.get(node, []):
            indegree[neighbor] -= 1
            if indegree[neighbor] == 0:
                queue.append(neighbor)
    return order
```

Bug: graph edges are reversed. depends_on means 'this node depends on those', so edges should go from dependency to dependent.

Fix: cycle detection returns wrong cycle path. It should return the actual cycle nodes.

```python
def find_cycle(graph: dict) -> list:
    visited = set()
    path = []
    def dfs(node):
        if node in visited:
            return path
        visited.add(node)
        path.append(node)
        for neighbor in graph.get(node, []):
            result = dfs(neighbor)
            if result:
                return result
        path.pop()
        return None
    for node in graph:
        result = dfs(node)
        if result:
            return result
    return []
```

Bug: visited set prevents re-entering nodes from different paths. Need separate 'in current path' tracking.

Fix: self-loop detection is missing.

```python
def has_cycle(graph: dict) -> bool:
    visited = set()
    rec_stack = set()
    def dfs(node):
        visited.add(node)
        rec_stack.add(node)
        for neighbor in graph.get(node, []):
            if neighbor not in visited:
                if dfs(neighbor):
                    return True
            elif neighbor in rec_stack:
                return True
        rec_stack.discard(node)
        return False
    for node in graph:
        if node not in visited:
            if dfs(node):
                return True
    return False
```

This actually works for self-loops too since neighbor==node is in rec_stack. But it fails for nodes not in graph keys. Fix: ensure all referenced nodes are checked.

Fix: adjacency list builder drops bidirectional edges.

```python
def build_adj(edges: list) -> dict:
    adj = {}
    for u, v in edges:
        adj[u] = adj.get(u, []) + [v]
    return adj
```

Should be undirected graph (both directions).

Fix: dependency graph builder doesn't handle missing dependencies gracefully.

```python
def build_dependency_graph(tasks: list) -> dict:
    graph = {t['id']: t['depends_on'] for t in tasks}
    visited = set()
    order = []
    def visit(node):
        if node in visited:
            return
        visited.add(node)
        for dep in graph[node]:
            visit(dep)
        order.append(node)
    for t in tasks:
        visit(t['id'])
    return {'order': order, 'is_valid': True, 'cycle': None}
```

Bug: KeyError when depends_on references a task not in the list.

Fix: topological sort uses wrong stack ordering. Result is reversed.

```python
def topological_order(adj: dict) -> list:
    """Return topological ordering of a DAG."""
    seen = set()
    stack = []
    def _dfs(v):
        seen.add(v)
        for w in adj.get(v, []):
            if w not in seen:
                _dfs(w)
        stack.insert(0, v)
    for v in adj:
        if v not in seen:
            _dfs(v)
    stack.reverse()
    return stack
```

Bug: insert(0, v) already gives correct order, but then reverse() flips it.

Fix: Kahn's algorithm doesn't initialize indegree for all nodes.

```python
def kahn_topo(graph: dict) -> list:
    """Kahn's algorithm for topological sort."""
    indeg = {}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    queue = [n for n in graph if indeg.get(n, 0) == 0]
    result = []
    while queue:
        n = queue.pop(0)
        result.append(n)
        for v in graph.get(n, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                queue.append(v)
    if len(result) != len(graph):
        raise ValueError("cycle detected")
    return result
```

Bug: nodes that only appear as targets (in adjacency lists) but not as keys in graph are never yielded.

Fix: cycle detection in directed graph misses back edges to ancestors beyond parent.

```python
def detect_cycle_directed(graph: dict) -> bool:
    """Return True if directed graph has a cycle."""
    white, gray, black = 0, 1, 2
    color = {n: white for n in graph}
    def dfs(u):
        color[u] = gray
        for v in graph.get(u, []):
            if color.get(v, white) == white:
                if dfs(v):
                    return True
            elif color[v] == gray:
                return True
        color[u] = white
        return False
    for n in graph:
        if color[n] == white:
            if dfs(n):
                return True
    return False
```

Bug: after finishing a node, color is set back to white instead of black.

Fix: topological sort with DFS doesn't handle nodes that have no outgoing edges but exist only as targets.

```python
def topo_dfs(edges: list) -> list:
    """Topological sort from edge list."""
    graph = {}
    for u, v in edges:
        graph.setdefault(u, []).append(v)
    visited = set()
    order = []
    def dfs(node):
        visited.add(node)
        for nb in graph.get(node, []):
            if nb not in visited:
                dfs(nb)
        order.append(node)
    for node in graph:
        if node not in visited:
            dfs(node)
    order.reverse()
    return order
```

Bug: sink nodes (no outgoing edges) that aren't graph keys are skipped.

Fix: cycle detection doesn't handle self-loops.

```python
def has_self_loop_or_cycle(graph: dict) -> str:
    """Return 'self-loop', 'cycle', or 'none'."""
    visited = set()
    rec = set()
    def dfs(node):
        visited.add(node)
        rec.add(node)
        for nb in graph.get(node, []):
            if nb not in visited:
                result = dfs(nb)
                if result:
                    return result
            elif nb in rec:
                return 'cycle'
        rec.discard(node)
        return None
    for n in graph:
        if n not in visited:
            r = dfs(n)
            if r:
                return r
    return 'none'
```

Bug: self-loops (node pointing to itself) are reported as 'cycle' not 'self-loop'.

Fix: topological sort with priority (lexicographic smallest) uses wrong data structure.

```python
def topo_sort_lex(graph: dict) -> list:
    """Return lexicographically smallest topological order."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    queue = sorted([n for n in graph if indeg[n] == 0])
    result = []
    while queue:
        node = queue.pop()
        result.append(node)
        for v in graph.get(node, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                queue.append(v)
                queue.sort()
    return result
```

Bug: queue.pop() takes from the end (largest), should take from front (smallest).

Fix: cycle detection returns True for undirected graph traversal revisiting parent.

```python
def has_cycle_undirected(adj: dict) -> bool:
    """Detect cycle in undirected graph."""
    visited = set()
    def dfs(node, parent):
        visited.add(node)
        for nb in adj.get(node, []):
            if nb not in visited:
                if dfs(nb, node):
                    return True
            elif nb != parent:
                return True
        return False
    for node in adj:
        if node not in visited:
            if dfs(node, None):
                return True
    return False
```

Bug: multi-edges between same two nodes give false positive. Parent check only works for single edge. Fix by tracking parent edge index instead.

Fix: topo sort counts only nodes in graph keys, missing nodes that appear only in adjacency lists.

```python
def topo_with_validation(graph: dict) -> tuple:
    """Return (order, is_dag). order is empty if not a DAG."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    q = [n for n in graph if indeg[n] == 0]
    order = []
    while q:
        n = q.pop(0)
        order.append(n)
        for v in graph.get(n, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)
    return (order, True) if len(order) == len(graph) else ([], False)
```

Bug: indeg dict has nodes from graph values but graph dict doesn't; len(graph) undercounts total nodes.

Fix: topo sort with iterative DFS has stack ordering bug.

```python
def iterative_topo(graph: dict) -> list:
    """Iterative DFS topological sort."""
    visited = set()
    result = []
    for start in graph:
        if start in visited:
            continue
        stack = [start]
        while stack:
            node = stack.pop()
            if node in visited:
                continue
            visited.add(node)
            result.append(node)
            for nb in graph.get(node, []):
                if nb not in visited:
                    stack.append(nb)
    return result
```

Bug: this is just DFS order, not topological order. Need to append after all children are processed.

Fix: cycle detection using indegrees gives wrong result when graph has isolated nodes.

```python
def is_dag(edges: list, nodes: list) -> bool:
    """Check if a graph defined by edges and node list is a DAG."""
    graph = {}
    indeg = {}
    for u, v in edges:
        graph.setdefault(u, []).append(v)
        indeg[v] = indeg.get(v, 0) + 1
    queue = [n for n in indeg if indeg[n] == 0]
    count = 0
    while queue:
        n = queue.pop(0)
        count += 1
        for v in graph.get(n, []):
            indeg[v] -= 1
            if indeg[v] == 0:
                queue.append(v)
    return count == len(nodes)
```

Bug: queue seed only considers nodes in indeg dict. Nodes with no incoming edges and no outgoing edges (isolated) are missed.

Fix: cycle length calculation is off by one.

```python
def shortest_cycle_length(graph: dict) -> int:
    """Return length of shortest cycle in directed graph, or -1 if acyclic."""
    min_len = float('inf')
    for start in graph:
        dist = {start: 0}
        queue = [start]
        while queue:
            u = queue.pop(0)
            for v in graph.get(u, []):
                if v == start:
                    min_len = min(min_len, dist[u])
                elif v not in dist:
                    dist[v] = dist[u] + 1
                    queue.append(v)
    return min_len if min_len != float('inf') else -1
```

Bug: cycle length should be dist[u] + 1 (the edge back to start counts).

Fix: topo sort with cycle error message doesn't show which nodes form the cycle.

```python
def topo_sort_verbose(graph: dict) -> list:
    """Topological sort that raises with cycle info."""
    UNVISITED, IN_PROGRESS, DONE = 0, 1, 2
    state = {n: UNVISITED for n in graph}
    order = []
    def dfs(node, path):
        state[node] = IN_PROGRESS
        path.append(node)
        for nb in graph.get(node, []):
            if state.get(nb, UNVISITED) == UNVISITED:
                dfs(nb, path)
            elif state[nb] == IN_PROGRESS:
                raise ValueError(f"Cycle detected")
        state[node] = DONE
        order.append(node)
        path.pop()
    for n in graph:
        if state[n] == UNVISITED:
            dfs(n, [])
    order.reverse()
    return order
```

Bug: error message doesn't include the cycle path.

Fix: parallel course scheduling doesn't count levels correctly.

```python
def min_semesters(n: int, relations: list) -> int:
    """Minimum semesters to complete all courses. relations[i] = [prev, next]."""
    graph = {i: [] for i in range(1, n + 1)}
    indeg = {i: 0 for i in range(1, n + 1)}
    for prev, nxt in relations:
        graph[prev].append(nxt)
        indeg[nxt] += 1
    queue = [i for i in range(1, n + 1) if indeg[i] == 0]
    semesters = 0
    taken = 0
    while queue:
        next_q = []
        for c in queue:
            taken += 1
            for nb in graph[c]:
                indeg[nb] -= 1
                if indeg[nb] == 0:
                    next_q.append(nb)
        queue = next_q
    semesters += 1
    return semesters if taken == n else -1
```

Bug: semesters is incremented once after the loop instead of once per level.

Fix: topological sort silently returns partial order when cycle exists.

```python
def safe_topo(graph: dict) -> list:
    """Topological sort that returns empty list if cycle exists."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    q = [n for n in graph if indeg[n] == 0]
    order = []
    while q:
        node = q.pop(0)
        order.append(node)
        for v in graph[node]:
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)
    return order
```

Bug: doesn't check if all nodes are in order; returns partial result on cycle.

Fix: topo sort on task graph with string IDs and numeric priorities uses wrong comparison.

```python
import heapq

def priority_topo(graph: dict, priority: dict) -> list:
    """Topo sort preferring higher-priority tasks first."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    heap = [(priority[n], n) for n in graph if indeg[n] == 0]
    heapq.heapify(heap)
    result = []
    while heap:
        _, node = heapq.heappop(heap)
        result.append(node)
        for v in graph[node]:
            indeg[v] -= 1
            if indeg[v] == 0:
                heapq.heappush(heap, (priority[v], v))
    return result
```

Bug: heapq is a min-heap, so it picks lowest priority first. Need to negate for highest first.

Fix: topological sort on weighted DAG drops the weights.

```python
def topo_weighted(graph: dict) -> list:
    """Topo sort for weighted DAG. graph = {node: [(neighbor, weight), ...]}.
    Returns list of (node, max_dist_from_source)."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v, w in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    q = [n for n in graph if indeg[n] == 0]
    dist = {n: 0 for n in graph}
    order = []
    while q:
        u = q.pop(0)
        order.append(u)
        for v, w in graph.get(u, []):
            dist[v] = max(dist[v], dist[u])
            indeg[v] -= 1
            if indeg[v] == 0:
                q.append(v)
    return [(n, dist[n]) for n in order]
```

Bug: dist update ignores weight w.

Fix: all-paths topo sort doesn't yield all valid orderings.

```python
def all_topo_sorts(graph: dict) -> list:
    """Return all valid topological orderings."""
    indeg = {n: 0 for n in graph}
    for u in graph:
        for v in graph[u]:
            indeg[v] = indeg.get(v, 0) + 1
    results = []
    def backtrack(path):
        if len(path) == len(graph):
            results.append(path[:])
            return
        for n in graph:
            if indeg[n] == 0 and n not in path:
                indeg[n] = -1
                path.append(n)
                for v in graph[n]:
                    indeg[v] -= 1
                backtrack(path)
                path.pop()
                for v in graph[n]:
                    indeg[v] += 1
    backtrack([])
    return results
```

Bug: setting indeg[n] = -1 to mark as used, but should restore to 0 on backtrack, not just leave checks.

Fix: DFS traversal doesn't return nodes in correct finish order.

```python
def dfs_finish_order(graph: dict) -> list:
    """Return nodes in DFS finish order (post-order)."""
    visited = set()
    finish = []
    def dfs(node):
        visited.add(node)
        finish.append(node)
        for nb in graph.get(node, []):
            if nb not in visited:
                dfs(nb)
    for n in graph:
        if n not in visited:
            dfs(n)
    return finish
```

