Fix: BFS shortest path returns path length instead of actual path.

```python
def bfs_path(graph: dict, start, end) -> list:
    """Return shortest path from start to end as list of nodes."""
    if start == end:
        return [start]
    visited = {start}
    queue = [(start, 0)]
    while queue:
        node, dist = queue.pop(0)
        for nb in graph.get(node, []):
            if nb == end:
                return dist + 1
            if nb not in visited:
                visited.add(nb)
                queue.append((nb, dist + 1))
    return []
```

Bug: returns integer distance instead of path. Need to track parent pointers.

Fix: adjacency matrix to adjacency list conversion has off-by-one in indexing.

```python
def matrix_to_adj(matrix: list) -> dict:
    """Convert adjacency matrix to adjacency list."""
    n = len(matrix)
    adj = {}
    for i in range(n):
        adj[i] = []
        for j in range(1, n):
            if matrix[i][j]:
                adj[i].append(j)
    return adj
```

Bug: inner loop starts at 1 instead of 0, missing edges to node 0.

Fix: graph transpose has wrong edge direction.

```python
def transpose_graph(graph: dict) -> dict:
    """Return the transpose (reversed edges) of a directed graph."""
    result = {n: [] for n in graph}
    for u in graph:
        for v in graph[u]:
            result[u].append(v)
    return result
```

Bug: copies edges as-is instead of reversing them.

Fix: connected component counting is wrong for directed graphs treated as undirected.

```python
def count_components(edges: list, n: int) -> int:
    """Count connected components in undirected graph with n nodes (0-indexed)."""
    adj = {i: [] for i in range(n)}
    for u, v in edges:
        adj[u].append(v)
    visited = set()
    count = 0
    def dfs(node):
        visited.add(node)
        for nb in adj[node]:
            if nb not in visited:
                dfs(nb)
    for i in range(n):
        if i not in visited:
            dfs(i)
            count += 1
    return count
```

Bug: only adds edge u->v, not v->u. Should be undirected.

Fix: Dijkstra's algorithm doesn't handle disconnected nodes.

```python
import heapq

def dijkstra(graph: dict, start) -> dict:
    """Return shortest distances from start. graph = {node: [(nb, weight), ...]}."""
    dist = {start: 0}
    heap = [(0, start)]
    while heap:
        d, u = heapq.heappop(heap)
        if d > dist[u]:
            continue
        for v, w in graph[u]:
            nd = d + w
            if nd < dist.get(v, float('inf')):
                dist[v] = nd
                heapq.heappush(heap, (nd, v))
    return dist
```

Bug: graph[u] raises KeyError if u has no outgoing edges but was reached as a target.

Fix: graph coloring greedy algorithm skips color 0.

```python
def greedy_color(graph: dict) -> dict:
    """Assign colors (integers) to nodes. graph is adjacency list (undirected)."""
    colors = {}
    for node in graph:
        used = {colors[nb] for nb in graph[node] if nb in colors}
        color = 1
        while color in used:
            color += 1
        colors[node] = color
    return colors
```

Bug: starts at color 1 instead of 0, wasting a color index.

Fix: bipartite check returns wrong result due to incorrect neighbor color check.

```python
def is_bipartite(graph: dict) -> bool:
    """Check if undirected graph is bipartite using BFS."""
    color = {}
    for start in graph:
        if start in color:
            continue
        color[start] = 0
        queue = [start]
        while queue:
            node = queue.pop(0)
            for nb in graph.get(node, []):
                if nb not in color:
                    color[nb] = color[node]
                    queue.append(nb)
                elif color[nb] == color[node]:
                    return False
    return True
```

Bug: assigns same color to neighbor instead of opposite.

Fix: strongly connected components (Kosaraju) returns wrong grouping.

```python
def kosaraju_scc(graph: dict) -> list:
    """Return list of SCCs using Kosaraju's algorithm."""
    # Step 1: finish order
    visited = set()
    finish = []
    def dfs1(u):
        visited.add(u)
        for v in graph.get(u, []):
            if v not in visited:
                dfs1(v)
        finish.append(u)
    for n in graph:
        if n not in visited:
            dfs1(n)
    # Step 2: transpose
    trans = {n: [] for n in graph}
    for u in graph:
        for v in graph[u]:
            trans[v].append(u)
    # Step 3: DFS on transpose in reverse finish order
    visited.clear()
    sccs = []
    def dfs2(u, comp):
        visited.add(u)
        comp.append(u)
        for v in trans.get(u, []):
            if v not in visited:
                dfs2(v, comp)
    for n in finish:  # BUG: should be reversed
        if n not in visited:
            comp = []
            dfs2(n, comp)
            sccs.append(comp)
    return sccs
```

Bug: iterates finish in forward order instead of reversed.

Fix: DAG longest path returns 0 for single-node graph.

```python
def dag_longest_path(graph: dict) -> int:
    """Return length of longest path in a DAG (number of edges)."""
    dist = {}
    def dfs(u):
        if u in dist:
            return dist[u]
        max_d = 0
        for v in graph.get(u, []):
            max_d = max(max_d, 1 + dfs(v))
        dist[u] = max_d
        return max_d
    result = 0
    for n in graph:
        result = max(result, dfs(n))
    return result
```

Actually this returns 0 for a single node (correct — 0 edges). The real bug: it doesn't handle nodes that appear only as targets.

Fix: Bellman-Ford doesn't detect negative cycles.

```python
def bellman_ford(edges: list, n: int, src: int) -> dict:
    """Shortest paths from src. edges = [(u, v, w)]. Returns dist dict."""
    dist = {i: float('inf') for i in range(n)}
    dist[src] = 0
    for _ in range(n - 1):
        for u, v, w in edges:
            if dist[u] + w < dist[v]:
                dist[v] = dist[u] + w
    return dist
```

Bug: no negative cycle check after relaxation loop.

Fix: Floyd-Warshall uses wrong initialization for self-distances.

```python
def floyd_warshall(n: int, edges: list) -> list:
    """All-pairs shortest paths. edges = [(u, v, w)]."""
    INF = float('inf')
    dist = [[INF] * n for _ in range(n)]
    for u, v, w in edges:
        dist[u][v] = w
    for k in range(n):
        for i in range(n):
            for j in range(n):
                if dist[i][k] + dist[k][j] < dist[i][j]:
                    dist[i][j] = dist[i][k] + dist[k][j]
    return dist
```

Bug: dist[i][i] should be 0, not INF.

Fix: connected components with Union-Find has wrong union logic.

```python
def count_components_uf(n: int, edges: list) -> int:
