import math

def volatility_calc(prices, window=30, annualize=True):
    if len(prices) < 2:
        return []
    returns = []
    for i in range(1, len(prices)):
        if prices[i - 1] == 0:
            returns.append(0.0)
        else:
            returns.append((prices[i] - prices[i - 1]) / prices[i - 1])
    vol = []
    for i in range(window, len(returns) + 1):
        w = returns[i - window:i]
        mean = sum(w) / len(w)
        variance = sum((x - mean) ** 2 for x in w) / len(w)
        std = variance ** 0.5
        if annualize:
            std = variance * math.sqrt(252)
        vol.append(std)
