class TaskQueue:
    def __init__(self):
        self.tasks = []

    def push(self, task_id: str, priority: int):
        self.tasks.append((priority, task_id))
        self.tasks.sort(key=lambda x: x[0])

    def pop(self) -> str:
        if not self.tasks:
            return None
        return self.tasks.pop(0)[1]

    def peek(self) -> str:
        if not self.tasks:
            return None
        return self.tasks[0][1]

    def size(self) -> int:
        return len(self.tasks)
