def tokenize_sql(query: str) -> list[dict]:
    import re
    tokens = []
    keywords = {'SELECT', 'FROM', 'WHERE', 'AND', 'OR', 'INSERT', 'UPDATE', 'DELETE', 'INTO', 'VALUES', 'SET', 'ORDER', 'BY', 'GROUP', 'HAVING', 'JOIN', 'ON', 'AS', 'IN', 'NOT', 'NULL', 'LIKE', 'BETWEEN', 'LIMIT'}
    operators = {'=', '!=', '<', '>', '<=', '>=', '<>'}

    for m in re.finditer(r"'[^']*'|\w+|[=!<>]+|[,;().*]", query):
        val = m.group()
        if val.upper() in keywords:
            tokens.append({'type': 'keyword', 'value': val.upper()})
        elif val in operators:
            tokens.append({'type': 'operator', 'value': val})
        elif val.startswith("'"):
            tokens.append({'type': 'literal', 'value': val})
        elif val in ',;().*':
            tokens.append({'type': 'punctuation', 'value': val})
        else:
            tokens.append({'type': 'identifier', 'value': val})
    return tokens
```

