    result = {'browser': 'Unknown', 'version': '', 'os': 'Unknown', 'mobile': False}

    if 'Mobile' in ua or 'Android' in ua:
        result['mobile'] = True

    if 'Windows' in ua:
        result['os'] = 'Windows'
    elif 'Mac OS X' in ua:
        result['os'] = 'macOS'
    elif 'Linux' in ua:
        result['os'] = 'Linux'
    elif 'Android' in ua:
        result['os'] = 'Android'
    elif 'iPhone' in ua or 'iPad' in ua:
        result['os'] = 'iOS'

    browsers = [('Edg/', 'Edge'), ('Chrome/', 'Chrome'), ('Firefox/', 'Firefox'), ('Safari/', 'Safari')]
    for token, name in browsers:
        if token in ua:
            result['browser'] = name
            m = re.search(re.escape(token) + r'([\d.]+)', ua)
            if m:
                result['version'] = m.group(1)
            break
    return result
