def moving_zscore(values: list[float], window: int) -> list[float]:
    result = []
    for i in range(len(values)):
        start = max(0, i - window + 1)
        w = values[start:i + 1]
        if len(w) < 2:
            result.append(0.0)
            continue
        mean = sum(w) / len(w)
        var = sum((x - mean) ** 2 for x in w) / len(w)
        std = var ** 0.5
        if std == 0:
            result.append(0.0)
        else:
            result.append((values[i] - mean) / std)
    return result
```

