class CircuitBreaker:
    def __init__(self, failure_threshold: int, reset_timeout: float):
        self.failure_threshold = failure_threshold
        self.reset_timeout = reset_timeout
        self.consecutive_failures = 0
        self.last_failure_time = None
        self.state = 'closed'

    def call(self, timestamp: float, success: bool):
        if success:
            self.consecutive_failures = 0
            self.state = 'closed'
        else:
            self.consecutive_failures += 1
            self.last_failure_time = timestamp
            if self.consecutive_failures >= self.failure_threshold:
                self.state = 'open'

    def is_open(self, timestamp: float) -> bool:
        if self.state == 'open' and self.last_failure_time is not None:
            if timestamp - self.last_failure_time >= self.reset_timeout:
                self.state = 'half-open'
                return False
            return True
        return False
```

