def parse_currency(text: str) -> list[dict]:
    import re
    results = []
    pattern = r'(?:\(([\d,.]+(?:[MBK])?)\)\s*([A-Z]{3})|([\$€¥£])([\d,.]+(?:[MBK])?)|([\d,.]+(?:[MBK])?)\s*([A-Z]{3}|USD|EUR|GBP|JPY))'
    currency_symbols = {'$': 'USD', '€': 'EUR', '¥': 'JPY', '£': 'GBP'}
    multipliers = {'K': 1_000, 'M': 1_000_000, 'B': 1_000_000_000}

    def parse_num(s):
        s = s.replace(',', '')
        for suffix, mult in multipliers.items():
            if s.upper().endswith(suffix):
                return float(s[:-1]) * mult
        return float(s)

    for m in re.finditer(pattern, text):
        if m.group(1):  # (500) EUR - negative
            results.append({'amount': -parse_num(m.group(1)), 'currency': m.group(2)})
        elif m.group(3):  # $1,234.56
            results.append({'amount': parse_num(m.group(4)), 'currency': currency_symbols.get(m.group(3), 'USD')})
        elif m.group(5):  # 1.5M USD
            results.append({'amount': parse_num(m.group(5)), 'currency': m.group(6)})
    return results
```

