def diff_lists(old: list[dict], new: list[dict], key: str) -> dict:
    old_map = {item[key]: item for item in old}
    new_map = {item[key]: item for item in new}
    old_keys = set(old_map.keys())
    new_keys = set(new_map.keys())

    added = [new_map[k] for k in sorted(new_keys - old_keys)]
    removed = [old_map[k] for k in sorted(old_keys - new_keys)]
    modified = []
    unchanged = []
    for k in sorted(old_keys & new_keys):
        if old_map[k] != new_map[k]:
            modified.append(new_map[k])
        else:
            unchanged.append(new_map[k])
    return {'added': added, 'removed': removed, 'modified': modified, 'unchanged': unchanged}
