class Trie:
    def __init__(self):
        self.root = {}
        self.words = set()
    def insert(self, word: str):
        node = self.root
        for c in word:
            if c not in node:
                node[c] = {}
            node = node[c]
        node['$'] = True
        self.words.add(word)
    def search(self, word: str) -> bool:
        node = self.root
        for c in word:
            if c not in node:
                return False
            node = node[c]
        return '$' in node
    def starts_with(self, prefix: str) -> list[str]:
        return sorted([w for w in self.words if w.startswith(prefix)])
