def compact_ranges(nums: list[int]) -> str:
    if not nums:
        return ''
    nums = sorted(set(nums))
    ranges = []
    start = nums[0]
    end = nums[0]
    for n in nums[1:]:
        if n == end + 1:
            end = n
        else:
            ranges.append(f"{start}-{end}" if start != end else str(start))
            start = end = n
    ranges.append(f"{start}-{end}" if start != end else str(start))
    return ','.join(ranges)
