```python
def sanitize_html(html: str, allowed_tags: list[str] = None) -> str:
    import re
    if allowed_tags is None:
        allowed_tags = ['b', 'i', 'em', 'strong', 'a', 'p', 'br']

    def replace_tag(match):
        full = match.group(0)
        tag_match = re.match(r'</?\s*(\w+)', full)
        if not tag_match:
            return ''
        tag = tag_match.group(1).lower()
        if tag not in allowed_tags:
            return ''
        if tag == 'a' and not full.startswith('</'):
            href = re.search(r'href=["\'](.*?)["\'"]', full)
            if href:
                return f'<a href="{href.group(1)}">'
            return '<a>'
        if full.startswith('</'):
            return f'</{tag}>'
        return f'<{tag}>'

    return re.sub(r'<[^>]+>', replace_tag, html)
```

