def binary_search(arr: list, target, key=None) -> int:
    lo, hi = 0, len(arr) - 1
    while lo <= hi:
        mid = (lo + hi) // 2
        val = key(arr[mid]) if key else arr[mid]
        tgt = key(target) if key and not isinstance(target, (int, float, str)) else target
        if val == tgt:
            return mid
        elif val < tgt:
            lo = mid + 1
        else:
            hi = mid - 1
    return -1
