def match_rules(data: dict, rules: list[dict]) -> list[str]:
    matched = []
    for rule in rules:
        field = rule['field']
        if field not in data:
            continue
        val = data[field]
        target = rule['value']
        op = rule['operator']

        try:
            if op == 'eq' and val == target:
                matched.append(rule['id'])
            elif op == 'ne' and val != target:
                matched.append(rule['id'])
            elif op == 'gt' and val > target:
                matched.append(rule['id'])
            elif op == 'lt' and val < target:
                matched.append(rule['id'])
            elif op == 'gte' and val >= target:
                matched.append(rule['id'])
            elif op == 'lte' and val <= target:
                matched.append(rule['id'])
            elif op == 'contains' and target in val:
                matched.append(rule['id'])
            elif op == 'in' and val in target:
                matched.append(rule['id'])
        except TypeError:
            continue
    return matched
