def pivot_table(rows: list[dict], index: str, column: str, value: str, agg: str = 'sum') -> dict:
    from collections import defaultdict
    groups = defaultdict(lambda: defaultdict(list))
    for row in rows:
        groups[row[index]][row[column]].append(row[value])

    result = {}
    for idx, cols in groups.items():
        result[idx] = {}
        for col, vals in cols.items():
            if agg == 'sum':
                result[idx][col] = sum(vals)
            elif agg == 'count':
                result[idx][col] = len(vals)
            elif agg == 'mean':
                result[idx][col] = sum(vals) / len(vals) if vals else 0
    return result
