def schedule_tasks(tasks: list[dict]) -> list[dict]:
    task_map = {t['id']: t for t in tasks}
    in_degree = {t['id']: len(t.get('depends_on', [])) for t in tasks}
    dependents = {t['id']: [] for t in tasks}
    for t in tasks:
        for dep in t.get('depends_on', []):
            dependents[dep].append(t['id'])

    end_times = {}
    queue = [tid for tid, deg in in_degree.items() if deg == 0]
    result = []

    while queue:
        queue.sort()
        tid = queue.pop(0)
        task = task_map[tid]
        deps = task.get('depends_on', [])
        start = max((end_times[d] for d in deps), default=0)
        end = start + task['duration']
        end_times[tid] = end
        result.append({**task, 'start_time': start, 'end_time': end})

        for dep_id in dependents[tid]:
            in_degree[dep_id] -= 1
            if in_degree[dep_id] == 0:
                queue.append(dep_id)

    if len(result) != len(tasks):
        raise ValueError("Circular dependency detected")
    return result
```

