def parse_log_entry(line: str) -> dict:
    import re
    result = {'timestamp': '', 'level': '', 'message': '', 'metadata': {}}

    m = re.match(r'\[(\d{4}-\d{2}-\d{2} \d{2}:\d{2}:\d{2})\]\s+(\w+):\s+(.*)', line)
    if not m:
        return result

    result['timestamp'] = m.group(1)
    result['level'] = m.group(2)
    msg = m.group(3)

    meta_match = re.search(r'\(([^)]+)\)\s*$', msg)
    if meta_match:
        result['message'] = msg[:meta_match.start()].strip()
        pairs = meta_match.group(1).split(',')
        for pair in pairs:
            pair = pair.strip()
            if '=' in pair:
                k, v = pair.split('=', 1)
