class LRUCache:
    def __init__(self, max_size): self.max_size, self.cache, self.order = max_size, {}, []
    def _touch(self, key):
        if key in self.order: self.order.remove(key)
        self.order.append(key)
    def get(self, key):
        if key in self.cache: self._touch(key); return self.cache[key]
        return None
    def put(self, key, value):
        if key in self.cache: self.cache[key] = value; self._touch(key)
        else:
            if len(self.cache) >= self.max_size:
                oldest = self.order.pop(0); del self.cache[oldest]
            self.cache[key] = value; self.order.append(key)
    def size(self): return len(self.cache)
    def keys(self): return list(self.order)
