class TaskQueue:
    def __init__(self): self.pending, self.in_progress, self.completed = [], set(), set()
    def enqueue(self, task_id, priority=0):
        self.pending.append((priority, task_id)); self.pending.sort(key=lambda x:-x[0])
    def dequeue(self):
        if not self.pending: return None
        _, tid = self.pending.pop(0); self.in_progress.add(tid); return tid
    def complete(self, task_id):
        if task_id in self.in_progress:
            self.in_progress.discard(task_id); self.completed.add(task_id); return True
        return False
    def status(self):
