class SimpleRouter:
    def __init__(self): self.routes = []
    def add_route(self, pattern, handler):
        import re
        parts, params = pattern.split('/'), []
        regex_parts = []
        for p in parts:
            if p.startswith(':'):
                params.append(p[1:]); regex_parts.append('([^/]+)')
            else: regex_parts.append(re.escape(p))
        self.routes.append((re.compile('^'+'/'.join(regex_parts)+'$'), handler, params))
    def match(self, path):
        for regex, handler, params in self.routes:
            m = regex.match(path)
            if m: return (handler, {params[i]:m.group(i+1) for i in range(len(params))})
        return None
