def validate_config(config, schema):
    errors, result = [], dict(config)
    types = {'str':str,'int':int,'float':(int,float),'bool':bool,'list':list,'dict':dict}
    for key, spec in schema.items():
        if key not in result:
            if spec.get('required'): errors.append(f"Missing: {key}")
            elif 'default' in spec: result[key] = spec['default']
        elif spec.get('type') in types and not isinstance(result[key], types[spec['type']]):
            errors.append(f"{key}: expected {spec['type']}")
    return {'valid':len(errors)==0,'errors':errors,'config':result}
