class ConnectionPool:
    def __init__(self, max_size): self.max_size, self.next_id, self.active_conns = max_size, 0, set()
    def acquire(self):
        if len(self.active_conns) >= self.max_size: return -1
        cid = self.next_id; self.next_id += 1; self.active_conns.add(cid); return cid
    def release(self, conn_id):
        if conn_id in self.active_conns: self.active_conns.discard(conn_id); return True
        return False
    def active(self): return len(self.active_conns)
