def parse_size_string(s: str) -> int:
    import re
    m = re.match(r'([\d.]+)\s*(B|KB|MB|GB|TB)', s.strip(), re.IGNORECASE)
    if not m: raise ValueError(f"Invalid: {s}")
    v = float(m.group(1))
    mult = {'B':1,'KB':1024,'MB':1024**2,'GB':1024**3,'TB':1024**4}
    return int(v * mult[m.group(2).upper()])
