class StateMachine:
    def __init__(self, states, transitions, initial):
        self.states, self.transitions, self.state = set(states), transitions, initial
        self._history = [initial]
    def trigger(self, event):
        t = self.transitions.get(self.state, {})
        if event in t: self.state = t[event]; self._history.append(self.state); return True
        return False
    def current_state(self): return self.state
    def history(self): return list(self._history)
    def can_trigger(self, event): return event in self.transitions.get(self.state, {})
