def parse_ini_section(text: str) -> dict:
    result, current = {}, None
    for line in text.split('\n'):
        line = line.strip()
        if not line or line[0] in '#;': continue
        if line.startswith('[') and line.endswith(']'):
            current = line[1:-1].strip(); result[current] = {}
        elif '=' in line and current is not None:
            k, v = line.split('=', 1); result[current][k.strip()] = v.strip()
    return result
